import{_ as i,X as o,Y as n,Z as t,$ as e,a0 as c,a1 as r,a2 as p,F as d}from"./framework-ea2b8a12.js";const l={},s=p('<h1 id="开始使用" tabindex="-1"><a class="header-anchor" href="#开始使用" aria-hidden="true">#</a> 开始使用</h1><p>如需使用 SuzuBot ，则至少需要添加好友或者和 SuzuBot 处在同一群聊内。</p><h2 id="添加好友" tabindex="-1"><a class="header-anchor" href="#添加好友" aria-hidden="true">#</a> 添加好友</h2><p>如果您希望单独使用 SuzuBot 的功能而不希望在群组中使用，可以选择添加 SuzuBot 为好友。</p><p>可通过以下任意一种方式申请添加 SuzuBot 的好友（按照推荐度排序）：</p><ul><li>通过加入 SuzuBot 官方 QQ 群（955578812）进行申请</li><li>通过 QQ 号直接搜索申请（2706409070）</li></ul><p>需要注意的是，好友申请需要回答问题。请清楚直接的阐明来源和目的，模糊不清的答案可能不会通过。</p><div class="hint-container tip"><p class="hint-container-title">正确的申请</p><p>从何处得知Bot:</p><p><code>从 XXX 群来 / 群友推荐 / SuzuBot 网站</code></p><p>想要使用哪些功能:</p><p><code>使用 XXX 功能</code></p></div><div class="hint-container danger"><p class="hint-container-title">错误的申请</p><p>从何处得知Bot:</p><p><code>我不到啊</code></p><p>想要使用哪些功能:</p><p><code>小亮给他整个活</code></p></div><h2 id="邀请群聊" tabindex="-1"><a class="header-anchor" href="#邀请群聊" aria-hidden="true">#</a> 邀请群聊</h2><p>如果希望 SuzuBot 为您所在的群组提供服务，则需要邀请 SuzuBot 加入您的群组。</p><p>在此之前，请确认您符合以下条件：</p><ul><li>群组成员大于或等于 25 。如该群是正在发展的新兴群聊，则本条限制可放松</li><li>群组管理员同意 SuzuBot 加入群组</li><li>群组内同类型机器人数量不超过 1 个</li><li>群组管理员未被纳入拒绝服务名单</li></ul><p>向 SuzuBot 发送群组邀请需要事先添加好友，具体操作请参阅 <a href="#%E6%B7%BB%E5%8A%A0%E5%A5%BD%E5%8F%8B">添加好友</a></p><div class="hint-container warning"><p class="hint-container-title">注意</p><p>您应当发送 邀请入群 而非 推荐群聊</p></div><p>群组邀请发送后，一般会立即自动通过邀请。如果没有及时通过，请与开发者联系。</p><h2 id="管理员须知" tabindex="-1"><a class="header-anchor" href="#管理员须知" aria-hidden="true">#</a> 管理员须知</h2>',17),u=t("p",null,"烦请耐心观看",-1);function h(B,_){const a=d("RouterLink");return o(),n("div",null,[s,t("p",null,[e("对于群聊管理员，例如开关模块、退群等基础操作 SuzuBot 的方法位于 "),c(a,{to:"/module/basic/core.html"},{default:r(()=>[e("核心模块")]),_:1}),e(" 中")]),u])}const S=i(l,[["render",h],["__file","start.html.vue"]]);export{S as default};
